-- Category: Martial Arts -> martial_arts
-- Priority: Low
-- Durations: [4, 8], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Wing Chun Basics',
    'Wing Chun kung fu basics including chain punches, centerline theory, Siu Nim Tao form, and chi sau concepts',
    'martial_arts',
    'all_levels',
    8,
    5,
    'sport_specific',
